import { useEffect, useState } from "react";
import axios from "axios";

const API = "http://localhost:5000/api";

function RateBar({ value, color = "#22c55e" }) {
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
      <div style={{ flex: 1, height: 8, background: "#f3f4f6", borderRadius: 99 }}>
        <div style={{
          height: "100%", borderRadius: 99, background: color,
          width: `${Math.min(value, 100)}%`, transition: "width 0.8s ease",
        }} />
      </div>
      <span style={{ fontSize: 13, fontWeight: 700, color, minWidth: 36 }}>{value}%</span>
    </div>
  );
}

function ScoreRing({ value }) {
  const color = value >= 70 ? "#22c55e" : value >= 40 ? "#f59e0b" : "#ef4444";
  const R = 28, C = 2 * Math.PI * R;
  const dash = (value / 100) * C;
  return (
    <svg width={72} height={72} viewBox="0 0 72 72">
      <circle cx={36} cy={36} r={R} fill="none" stroke="#f3f4f6" strokeWidth={8} />
      <circle cx={36} cy={36} r={R} fill="none" stroke={color} strokeWidth={8}
        strokeDasharray={`${dash} ${C}`} strokeLinecap="round"
        transform="rotate(-90 36 36)" style={{ transition: "stroke-dasharray 0.8s ease" }} />
      <text x={36} y={40} textAnchor="middle" fontSize={14} fontWeight={800} fill={color}>{value}%</text>
    </svg>
  );
}

export default function OfficerScorecard() {
  const [officers, setOfficers] = useState([]);
  const [loading,  setLoading]  = useState(true);
  const [selected, setSelected] = useState(null);
  const [detail,   setDetail]   = useState(null);
  const [detailLoading, setDetailLoading] = useState(false);

  const token = localStorage.getItem("token");
  const headers = { Authorization: `Bearer ${token}` };

  useEffect(() => {
    async function fetchOfficers() {
      try {
        const res = await axios.get(`${API}/admin/authorities`, { headers });
        setOfficers(res.data?.data || res.data || []);
      } catch (err) {
        console.error("Scorecard fetch error:", err);
      } finally {
        setLoading(false);
      }
    }
    fetchOfficers();
  }, []);

  async function selectOfficer(officer) {
    setSelected(officer);
    setDetailLoading(true);
    try {
      const res = await axios.get(
        `${API}/complaints/stats/authority/${officer._id}`,
        { headers }
      );
      setDetail(res.data?.data || null);
    } catch {
      setDetail(null);
    } finally {
      setDetailLoading(false);
    }
  }

  return (
    <div style={{ fontFamily: "'Segoe UI', system-ui, sans-serif" }}>
      <div style={{ marginBottom: 24 }}>
        <h1 style={{ fontSize: 24, fontWeight: 800, color: "#111827", margin: 0 }}>🏆 Officer Scorecard</h1>
        <p style={{ fontSize: 13, color: "#6b7280", marginTop: 4 }}>Performance metrics for all authority officers</p>
      </div>

      {loading ? (
        <div style={{ textAlign: "center", padding: 60, color: "#9ca3af" }}>Loading…</div>
      ) : (
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 20 }}>

          {/* Officer list */}
          <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
            {officers.length === 0 ? (
              <div style={{ background: "#fff", border: "1px solid #e5e7eb", borderRadius: 14, padding: 40, textAlign: "center" }}>
                <div style={{ fontSize: 36, marginBottom: 8 }}>📭</div>
                <p style={{ color: "#6b7280" }}>No authority officers found</p>
              </div>
            ) : officers.map(o => {
              const total    = o.totalCompleted + o.totalDisputed || 0;
              const rate     = total > 0 ? Math.round((o.totalCompleted / (o.totalComplaintsAssigned || 1)) * 100) : 0;
              const isActive = selected?._id === o._id;
              return (
                <div
                  key={o._id}
                  onClick={() => selectOfficer(o)}
                  style={{
                    background: "#fff",
                    border: `2px solid ${isActive ? "#1a56db" : "#e5e7eb"}`,
                    borderRadius: 14, padding: "16px 20px", cursor: "pointer",
                    boxShadow: isActive ? "0 0 0 3px rgba(26,86,219,0.1)" : "0 1px 4px rgba(0,0,0,0.05)",
                    display: "flex", alignItems: "center", gap: 16,
                  }}
                >
                  <ScoreRing value={rate} />
                  <div style={{ flex: 1 }}>
                    <div style={{ fontSize: 14, fontWeight: 700, color: "#111827" }}>
                      {o.ward} — {o.department}
                    </div>
                    <div style={{ fontSize: 12, color: "#6b7280", marginTop: 3 }}>
                      {o.totalComplaintsAssigned || 0} assigned · {o.totalCompleted || 0} completed · {o.totalDisputed || 0} disputed
                    </div>
                    <div style={{ marginTop: 8 }}>
                      <RateBar value={rate} color={rate >= 70 ? "#22c55e" : rate >= 40 ? "#f59e0b" : "#ef4444"} />
                    </div>
                  </div>
                </div>
              );
            })}
          </div>

          {/* Detail panel */}
          <div style={{
            background: "#fff", border: "1px solid #e5e7eb", borderRadius: 14,
            padding: 28, boxShadow: "0 1px 4px rgba(0,0,0,0.05)",
            position: "sticky", top: 20, alignSelf: "start",
          }}>
            {!selected ? (
              <div style={{ textAlign: "center", padding: "40px 0", color: "#9ca3af" }}>
                <div style={{ fontSize: 40, marginBottom: 12 }}>👆</div>
                <p>Select an officer to view details</p>
              </div>
            ) : detailLoading ? (
              <div style={{ textAlign: "center", padding: "40px 0", color: "#9ca3af" }}>Loading…</div>
            ) : (
              <>
                <h2 style={{ fontSize: 18, fontWeight: 800, color: "#111827", margin: "0 0 4px" }}>
                  {selected.ward} — {selected.department}
                </h2>
                <p style={{ fontSize: 13, color: "#6b7280", marginBottom: 24 }}>Officer performance breakdown</p>

                {/* Big stats */}
                <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12, marginBottom: 24 }}>
                  {[
                    { label: "Total Assigned", value: detail?.totalAssigned ?? selected.totalComplaintsAssigned ?? 0, color: "#3b82f6" },
                    { label: "Completed",      value: detail?.completed     ?? selected.totalCompleted           ?? 0, color: "#22c55e" },
                    { label: "Pending",        value: detail?.pending       ?? 0,                                      color: "#f59e0b" },
                    { label: "Disputed",       value: detail?.disputed      ?? selected.totalDisputed            ?? 0, color: "#ef4444" },
                  ].map(s => (
                    <div key={s.label} style={{
                      background: "#f9fafb", borderRadius: 10, padding: "14px 16px",
                      border: "1px solid #e5e7eb",
                    }}>
                      <div style={{ fontSize: 24, fontWeight: 800, color: s.color }}>{s.value}</div>
                      <div style={{ fontSize: 12, color: "#6b7280", marginTop: 2 }}>{s.label}</div>
                    </div>
                  ))}
                </div>

                {/* Rate bars */}
                <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
                  <div>
                    <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 6 }}>
                      <span style={{ fontSize: 13, fontWeight: 600, color: "#374151" }}>Completion Rate</span>
                    </div>
                    <RateBar
                      value={detail?.completionRate ?? Math.round(((selected.totalCompleted || 0) / (selected.totalComplaintsAssigned || 1)) * 100)}
                      color="#22c55e"
                    />
                  </div>
                  <div>
                    <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 6 }}>
                      <span style={{ fontSize: 13, fontWeight: 600, color: "#374151" }}>Dispute Rate</span>
                    </div>
                    <RateBar
                      value={detail?.disputeRate ?? Math.round(((selected.totalDisputed || 0) / (selected.totalComplaintsAssigned || 1)) * 100)}
                      color="#ef4444"
                    />
                  </div>
                  <div style={{
                    background: "#f9fafb", borderRadius: 10, padding: "14px 16px",
                    border: "1px solid #e5e7eb", display: "flex", justifyContent: "space-between",
                  }}>
                    <span style={{ fontSize: 13, color: "#6b7280" }}>Avg. Resolution Time</span>
                    <span style={{ fontSize: 14, fontWeight: 700, color: "#111827" }}>
                      {detail?.avgCompletionDays ?? selected.avgCompletionDays ?? 0} days
                    </span>
                  </div>
                </div>
              </>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
